import React, { useState, useEffect } from 'react';
import { getIdeas } from '../services/api';
import CreateIdeaForm from '../components/CreateIdeaForm';
import SearchBar from '../components/SearchBar';
import IdeaList from '../components/IdeaList';

const Dashboard = () => {
    const [ideas, setIdeas] = useState([]);
    const [filteredIdeas, setFilteredIdeas] = useState([]);
    const [searchTerm, setSearchTerm] = useState('');
    const [loading, setLoading] = useState(true);

    const fetchIdeas = async () => {
        try {
            setLoading(true);
            const { data } = await getIdeas();
            setIdeas(data);
            setFilteredIdeas(data);
        } catch (error) {
            console.error('Failed to fetch ideas:', error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchIdeas();
    }, []);

    useEffect(() => {
        const filtered = ideas.filter(idea =>
            idea.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
            idea.author.toLowerCase().includes(searchTerm.toLowerCase())
        );
        setFilteredIdeas(filtered);
    }, [searchTerm, ideas]);

    const handleUpdate = () => {
        fetchIdeas();
    };

    if (loading) {
        return (
            <div className="container">
                <div className="loading">Loading ideas...</div>
            </div>
        );
    }

    return (
        <div className="container">
            <header className="header">
                <h1>💡 IdeaSpark</h1>
                <p>Pitch, upvote, and spark great ideas!</p>
            </header>

            <div className="form-section">
                <CreateIdeaForm onIdeaCreated={handleUpdate} />
            </div>

            <SearchBar searchTerm={searchTerm} onSearchChange={setSearchTerm} />

            <IdeaList ideas={filteredIdeas} onUpdate={handleUpdate} />
        </div>
    );
};

export default Dashboard;
